  totalFrete: number;
  totalGeral: number;
}

const SummaryFooter: React.FC<SummaryFooterProps> = ({ diarista, totalFrete, totalGeral }) => {
  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

