export default SummaryFooter;

import React, { useState, useEffect, useCallback } from 'react';
import HeaderForm from './components/HeaderForm';
import DataTable from './components/DataTable';
import SummaryFooter from './components/SummaryFooter';
import { PerfilVeiculo, ReportHeader, RomaneioItem, Regiao } from './types';
import { FRETE_TABLE } from './constants';
import { parsePdfData } from './services/pdfParser';
import { FileUp, FileSpreadsheet, FileText, Plus, Loader2 } from 'lucide-react';
import * as XLSX from 'xlsx';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

const App: React.FC = () => {
  const [header, setHeader] = useState<ReportHeader>({
    prestador: '',
    perfilVeiculo: PerfilVeiculo.VUC,
    placa: '',
    dataPrestacao: new Date().toLocaleDateString('pt-BR'),
    diarista: 0
  });

  const [items, setItems] = useState<RomaneioItem[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  // Recalculate values for a single item
  const calculateItemValues = (item: Partial<RomaneioItem>, perfil: PerfilVeiculo): RomaneioItem => {
    const kmRodado = Math.max(0, (item.kmChegada || 0) - (item.kmSaida || 0));
    const valorFrete = FRETE_TABLE[item.regiao || Regiao.R1][perfil];
    const valorTotal = valorFrete + (item.retornoZero || 0);

    return {
      ...item,
      kmRodado,
      valorFrete,
      valorTotal
    } as RomaneioItem;
  };

  // Update all items when profile changes
  useEffect(() => {
    setItems(prevItems => prevItems.map(item => calculateItemValues(item, header.perfilVeiculo)));
  }, [header.perfilVeiculo]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    try {
      const { items: extractedItems, plaque, diarista } = await parsePdfData(file);

      const newItems = extractedItems.map(item => 
        calculateItemValues(item, header.perfilVeiculo)
      );

      setHeader(prev => ({ ...prev, placa: plaque, diarista: diarista }));
      setItems(newItems);
    } catch (error) {
      console.error('Error parsing PDF:', error);
      alert('Erro ao processar PDF. Verifique o formato do arquivo.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleUpdateItem = (id: string, updates: Partial<RomaneioItem>) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        return calculateItemValues({ ...item, ...updates }, header.perfilVeiculo);
      }
      return item;
    }));
  };

  const handleDeleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const handleAddItem = () => {
    const newItem: Partial<RomaneioItem> = {
      id: Math.random().toString(36).substr(2, 9),
      data: new Date().toLocaleDateString('pt-BR'),
      romaneio: '',
      regiao: Regiao.R1,
      kmSaida: 0,
      kmChegada: 0,
      retornoZero: 0
    };
    setItems(prev => [...prev, calculateItemValues(newItem, header.perfilVeiculo)]);
  };

  const exportExcel = () => {
    const data = items.map(i => ({
      Data: i.data,
      Romaneio: i.romaneio,
      Região: i.regiao,
      'KM Saída': i.kmSaida,
      'KM Chegada': i.kmChegada,
      'KM Rodado': i.kmRodado,
      'Retorno 0': i.retornoZero,
      'Valor Frete': i.valorFrete,
      'Valor Total': i.valorTotal
    }));

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Prestação de Contas");
    XLSX.writeFile(wb, `prestacao_contas_${header.prestador || 'frete'}.xlsx`);
  };

  const exportPdf = () => {
    const doc = new jsPDF('l', 'mm', 'a4');

    doc.setFontSize(18);
    doc.text('Relatório de Prestação de Contas', 14, 20);

    doc.setFontSize(10);
    doc.text(`Prestador: ${header.prestador}`, 14, 30);
    doc.text(`Perfil: ${header.perfilVeiculo}`, 14, 35);
    doc.text(`Placa: ${header.placa}`, 14, 40);
    doc.text(`Data: ${header.dataPrestacao}`, 14, 45);

    autoTable(doc, {
      startY: 55,
      head: [['Data', 'Romaneio', 'Região', 'KM Saída', 'KM Chegada', 'KM Rodado', 'Retorno 0', 'V. Frete', 'V. Total']],
      body: items.map(i => [
        i.data, 
        i.romaneio, 
        i.regiao, 
        i.kmSaida, 
        i.kmChegada, 
        i.kmRodado, 
        `R$ ${i.retornoZero.toFixed(2)}`, 
        `R$ ${i.valorFrete.toFixed(2)}`, 
        `R$ ${i.valorTotal.toFixed(2)}`
      ]),
    });

    const finalY = (doc as any).lastAutoTable.finalY || 150;
    doc.text(`Diarista: R$ ${header.diarista.toFixed(2)}`, 14, finalY + 10);
    doc.text(`Total Frete: R$ ${totalFrete.toFixed(2)}`, 14, finalY + 15);
    doc.text(`TOTAL GERAL: R$ ${totalGeral.toFixed(2)}`, 14, finalY + 20);

    doc.save(`prestacao_contas_${header.prestador || 'frete'}.pdf`);
  };

  const totalFrete = items.reduce((sum, i) => sum + i.valorFrete, 0);
  const totalGeral = items.reduce((sum, i) => sum + i.valorTotal, 0) + header.diarista;

  return (
    <div className="min-h-screen p-4 md:p-8 max-w-7xl mx-auto">
      <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-extrabold text-gray-900 flex items-center gap-2">
            <span className="p-2 bg-blue-600 text-white rounded-lg"><FileText /></span>
            Prestação de Contas de Freteiros
          </h1>
          <p className="text-gray-500 mt-1">Gestão inteligente e automatizada de romaneios.</p>
        </div>

        <div className="flex items-center gap-2 flex-wrap">
          <label className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-semibold cursor-pointer transition-all shadow-sm">
            {isProcessing ? <Loader2 className="animate-spin" /> : <FileUp size={20} />}
            {isProcessing ? 'Processando...' : 'Importar PDF'}
            <input type="file" accept=".pdf" onChange={handleFileUpload} className="hidden" disabled={isProcessing} />
          </label>
          <button 
            onClick={exportExcel}
            className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg font-semibold transition-all shadow-sm"
          >
            <FileSpreadsheet size={20} />
            Excel
          </button>
          <button 
            onClick={exportPdf}
            className="flex items-center gap-2 bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-lg font-semibold transition-all shadow-sm"
          >
            <FileText size={20} />
            PDF
          </button>
        </div>
      </header>

      <HeaderForm header={header} onChange={setHeader} />

      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-bold text-gray-800">Itens do Lançamento</h3>
        <button 
          onClick={handleAddItem}
          className="flex items-center gap-2 text-blue-600 hover:text-blue-700 font-semibold text-sm transition-colors px-3 py-1 rounded-md hover:bg-blue-50"
        >
          <Plus size={16} /> Adicionar Romaneio
        </button>
      </div>

      <DataTable 
        items={items} 
        onUpdateItem={handleUpdateItem} 
        onDeleteItem={handleDeleteItem} 
      />

      <SummaryFooter 
        diarista={header.diarista} 
        totalFrete={totalFrete} 
        totalGeral={totalGeral} 
      />

      <footer className="mt-12 text-center text-gray-400 text-sm border-t pt-8">
        &copy; {new Date().getFullYear()} - Sistema de Prestação de Contas de Freteiros Profissional
      </footer>
    </div>
  );
};

export default App;

import * as pdfjs from 'pdfjs-dist';
import { CIADE_REGIAO_MAP } from '../constants';
import { Regiao, RomaneioItem } from '../types';

// PDF.js worker setup using the same CDN provider (esm.sh) to ensure compatibility and version matching
pdfjs.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@5.4.449/build/pdf.worker.min.mjs`;

export const parsePdfData = async (file: File): Promise<{ items: Partial<RomaneioItem>[], plaque: string, diarista: number }> => {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;

  let fullText = '';
  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const textContent = await page.getTextContent();
    // Use a more robust way to join text items
    const pageText = textContent.items.map((item: any) => item.str).join(' ');
    fullText += pageText + ' ';
  }

  // Identificação de Romaneios: Romaneio AAAA/MM/DD-NNN
  const romaneioRegex = /Romaneio\s+(\d{4}\/\d{2}\/\d{2})-(\d+)/g;
  const items: Partial<RomaneioItem>[] = [];
  let match;

  while ((match = romaneioRegex.exec(fullText)) !== null) {
    const rawDate = match[1];
    const romaneioNum = match[2];

    // Format Date from YYYY/MM/DD to DD/MM/YYYY
    const [y, m, d] = rawDate.split('/');
    const formattedDate = `${d}/${m}/${y}`;

    items.push({
      id: Math.random().toString(36).substr(2, 9),
      data: formattedDate,
      romaneio: romaneioNum,
      kmSaida: 0,
      kmChegada: 0,
      retornoZero: 0
    });
  }

  // Placa: Veiculo JSX-0811
  const plaqueMatch = /Veiculo\s+([A-Z0-9-]{7,8})/i.exec(fullText);
  const plaque = plaqueMatch ? plaqueMatch[1].toUpperCase() : '';

  // Diarista: 2.003 DIARISTA AJUDANTE
  const diarista = fullText.includes('2.003 DIARISTA AJUDANTE') ? 80.0 : 0.0;

  // Region logic: Rota <NOME DA CIDADE>
  const rotaRegex = /Rota\s+([A-ZÁÀÂÃÉÈÊÍÏÓÔÕÖÚÇ\s']+)/gi;
  const citiesFound: Regiao[] = [];
  let rotaMatch;
  while ((rotaMatch = rotaRegex.exec(fullText)) !== null) {
    const cityName = rotaMatch[1].trim().toUpperCase();
    const regiao = CIADE_REGIAO_MAP[cityName] || Regiao.R1;
    citiesFound.push(regiao);
  }

  // Zip the found regions to the items
  items.forEach((item, index) => {
    item.regiao = citiesFound[index] || Regiao.R1;
  });

  return { items, plaque, diarista };
};

export enum PerfilVeiculo {
  VUC = 'VUC',
  TOCO = 'TOCO',
  TRUCK = 'TRUCK'
}

export enum Regiao {
  R1 = 'REGIÃO 1',
  R2 = 'REGIÃO 2',
  R3 = 'REGIÃO 3',
  R4 = 'REGIÃO 4',
  R5 = 'REGIÃO 5',
  R6 = 'REGIÃO 6',
  NOT_FOUND = 'REGIÃO NÃO IDENTIFICADA'
}

