}

import * as pdfjs from 'pdfjs-dist';
import { CIADE_REGIAO_MAP } from '../constants';
import { Regiao, RomaneioItem } from '../types';

pdfjs.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@5.4.449/build/pdf.worker.min.mjs`;

const normalizeText = (text: string) => {
  return text.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toUpperCase().trim();
};

export const parsePdfData = async (file: File): Promise<{ items: Partial<RomaneioItem>[], plaque: string }> => {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;

  let fullText = '';
  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const textContent = await page.getTextContent();
    const pageText = textContent.items.map((item: any) => item.str).join(' ');
    fullText += pageText + ' [PAGE_BREAK] ';
  }

  // 1. Identify Romaneio Headers and split into blocks
  const romaneioHeaderRegex = /Romaneio\s+(\d{4}\/\d{2}\/\d{2})-(\d+)/g;
  const blocks: { text: string, data: string, romaneio: string }[] = [];
  let match;
  const indices: number[] = [];

  while ((match = romaneioHeaderRegex.exec(fullText)) !== null) {
    indices.push(match.index);
  }

  for (let i = 0; i < indices.length; i++) {
    const start = indices[i];
    const end = indices[i + 1] || fullText.length;
    const blockText = fullText.substring(start, end);

    // Extract basic info again from the start of the block
    const infoMatch = /Romaneio\s+(\d{4}\/\d{2}\/\d{2})-(\d+)/.exec(blockText);
    if (infoMatch) {
      const [y, m, d] = infoMatch[1].split('/');
      blocks.push({
        text: blockText,
        data: `${d}/${m}/${y}`,
        romaneio: infoMatch[2]
      });
    }
  }

  // 2. Extract global Placa (usually same for all romaneios in one PDF)
  const plaqueMatch = /Veiculo\s+([A-Z0-9-]{7,8})/i.exec(fullText);
  const plaque = plaqueMatch ? plaqueMatch[1].toUpperCase() : '';

  // 3. Process each block
  const items: Partial<RomaneioItem>[] = blocks.map(block => {
    // Rota -> Região
    const rotaMatch = /Rota\s+([A-ZÁÀÂÃÉÈÊÍÏÓÔÕÖÚÇ\s']+?)(?:\s{2,}|[PAGE_BREAK]|$)/i.exec(block.text);
    let regiao = Regiao.NOT_FOUND;
    if (rotaMatch) {
      const city = normalizeText(rotaMatch[1]);
      regiao = CIADE_REGIAO_MAP[city] || Regiao.NOT_FOUND;
    }

    // KMs
    const kmInicialMatch = /KM Inicial\s+(\d+)/i.exec(block.text);
    const kmFinalMatch = /KM Final\s+(\d+)/i.exec(block.text);

    const kmSaida = kmInicialMatch ? parseInt(kmInicialMatch[1]) : null;
    const kmChegada = kmFinalMatch ? parseInt(kmFinalMatch[1]) : null;

    // Diarista
    const hasDiarista = /DIARISTA AJUDANTE/i.test(block.text);

    return {
      id: Math.random().toString(36).substr(2, 9),
      data: block.data,
      romaneio: block.romaneio,
      regiao,
      kmSaida,
      kmChegada,
      diarista: hasDiarista ? 80.0 : 0.0,
      retornoZero: 0
    };
  });

  return { items, plaque };
};

import React, { useState, useEffect } from 'react';
import HeaderForm from './components/HeaderForm';
import DataTable from './components/DataTable';
import SummaryFooter from './components/SummaryFooter';
import { PerfilVeiculo, ReportHeader, RomaneioItem, Regiao } from './types';
import { FRETE_TABLE } from './constants';
import { parsePdfData } from './services/pdfParser';
import { FileUp, FileSpreadsheet, FileText, Plus, Loader2 } from 'lucide-react';
import * as XLSX from 'xlsx';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

const App: React.FC = () => {
  const [header, setHeader] = useState<ReportHeader>({
    prestador: '',
    perfilVeiculo: PerfilVeiculo.VUC,
    placa: '',
    dataPrestacao: new Date().toLocaleDateString('pt-BR')
  });

  const [items, setItems] = useState<RomaneioItem[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const calculateItemValues = (item: Partial<RomaneioItem>, perfil: PerfilVeiculo): RomaneioItem => {
    const kmSaida = item.kmSaida ?? null;
    const kmChegada = item.kmChegada ?? null;
    const kmRodado = (kmSaida !== null && kmChegada !== null) ? Math.max(0, kmChegada - kmSaida) : 0;

    const valorFrete = FRETE_TABLE[item.regiao || Regiao.NOT_FOUND][perfil];
    const valorTotal = valorFrete + (item.retornoZero || 0) + (item.diarista || 0);

    return {
      ...item,
      kmSaida,
      kmChegada,
      kmRodado,
      valorFrete,
      valorTotal
    } as RomaneioItem;
  };

  useEffect(() => {
    setItems(prevItems => prevItems.map(item => calculateItemValues(item, header.perfilVeiculo)));
  }, [header.perfilVeiculo]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    try {
      const { items: extractedItems, plaque } = await parsePdfData(file);
      const newItems = extractedItems.map(item => calculateItemValues(item, header.perfilVeiculo));
      setHeader(prev => ({ ...prev, placa: plaque }));
      setItems(newItems);
    } catch (error) {
      console.error('Error parsing PDF:', error);
      alert('Erro ao processar PDF. Verifique o formato do arquivo.');
    } finally {
      setIsProcessing(false);
      event.target.value = '';
    }
  };

  const handleUpdateItem = (id: string, updates: Partial<RomaneioItem>) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        return calculateItemValues({ ...item, ...updates }, header.perfilVeiculo);
      }
      return item;
    }));
  };

  const handleDeleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const handleAddItem = () => {
    const newItem: Partial<RomaneioItem> = {
      id: Math.random().toString(36).substr(2, 9),
      data: new Date().toLocaleDateString('pt-BR'),
      romaneio: '',
      regiao: Regiao.NOT_FOUND,
      kmSaida: null,
      kmChegada: null,
      retornoZero: 0,
      diarista: 0
    };
    setItems(prev => [...prev, calculateItemValues(newItem, header.perfilVeiculo)]);
  };

  const totalFrete = items.reduce((sum, i) => sum + i.valorFrete, 0);
  const totalDiarista = items.reduce((sum, i) => sum + i.diarista, 0);
  const totalGeral = items.reduce((sum, i) => sum + i.valorTotal, 0);

  const exportExcel = () => {
    const data = items.map(i => ({
      Data: i.data,
      Romaneio: i.romaneio,
      Região: i.regiao,
      'KM Saída': i.kmSaida,
      'KM Chegada': i.kmChegada,
      'KM Rodado': i.kmRodado,
      'Diarista': i.diarista,
      'Retorno 0': i.retornoZero,
      'Valor Frete': i.valorFrete,
      'Valor Total': i.valorTotal
    }));
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Prestação");
    XLSX.writeFile(wb, `prestacao_${header.prestador || 'frete'}.xlsx`);
  };

  const exportPdf = () => {
    const doc = new jsPDF('l', 'mm', 'a4');
    doc.text('Prestação de Contas de Freteiros', 14, 15);
    autoTable(doc, {
      startY: 25,
      head: [['Data', 'Romaneio', 'Região', 'KM Saída', 'KM Chegada', 'KM Rodado', 'Diarista', 'Retorno 0', 'V. Frete', 'V. Total']],
      body: items.map(i => [i.data, i.romaneio, i.regiao, i.kmSaida || '-', i.kmChegada || '-', i.kmRodado, i.diarista, i.retornoZero, i.valorFrete, i.valorTotal]),
    });
    doc.save(`prestacao_${header.prestador || 'frete'}.pdf`);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 max-w-7xl mx-auto">
      <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-extrabold text-gray-900 flex items-center gap-2">
            <span className="p-2 bg-blue-600 text-white rounded-lg"><FileText /></span>
            Prestação de Contas
          </h1>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <label className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-semibold cursor-pointer transition-all shadow-sm">
            {isProcessing ? <Loader2 className="animate-spin" /> : <FileUp size={20} />}
            {isProcessing ? 'Processando...' : 'Importar PDF'}
            <input type="file" accept=".pdf" onChange={handleFileUpload} className="hidden" disabled={isProcessing} />
          </label>
          <button onClick={exportExcel} className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg font-semibold shadow-sm"><FileSpreadsheet size={20} /> Excel</button>
          <button onClick={exportPdf} className="flex items-center gap-2 bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-lg font-semibold shadow-sm"><FileText size={20} /> PDF</button>
        </div>
      </header>

      <HeaderForm header={header} onChange={setHeader} />

      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-bold text-gray-800">Itens do Lançamento</h3>
        <button onClick={handleAddItem} className="flex items-center gap-2 text-blue-600 hover:text-blue-700 font-semibold text-sm transition-colors px-3 py-1 rounded-md hover:bg-blue-50"><Plus size={16} /> Adicionar</button>
      </div>

      <DataTable items={items} onUpdateItem={handleUpdateItem} onDeleteItem={handleDeleteItem} />

      <SummaryFooter diarista={totalDiarista} totalFrete={totalFrete} totalGeral={totalGeral} />
    </div>
  );
};

export default App;

